const menu=document.querySelector('[data-mobile-menu]');const open=document.querySelector('[data-menu-open]');const close=document.querySelector('[data-menu-close]');const theme=document.querySelector('[data-theme-toggle]');let previous=null;function closeMenu(){if(menu.open)menu.close();open?.setAttribute('aria-expanded','false');previous?.focus()}open?.addEventListener('click',()=>{previous=document.activeElement;menu.showModal();open.setAttribute('aria-expanded','true');close.focus()});close?.addEventListener('click',closeMenu);menu?.addEventListener('click',event=>{if(event.target===menu)closeMenu()});menu?.addEventListener('cancel',event=>{event.preventDefault();closeMenu()});document.querySelectorAll('.mobile-menu a').forEach(link=>link.addEventListener('click',closeMenu));theme?.addEventListener('click',()=>{const dark=document.documentElement.dataset.theme==='dark';document.documentElement.dataset.theme=dark?'light':'dark';theme.textContent=dark?'Tema':'Ljust';theme.setAttribute('aria-label',dark?'Byt till mörkt tema':'Byt till ljust tema')});document.querySelector('[data-search]')?.addEventListener('submit',event=>{event.preventDefault();const query=event.currentTarget.querySelector('input').value.trim();event.currentTarget.querySelector('[data-search-result]').textContent=query?`Sökningen efter "${query}" är förberedd för sökytan i prototypen.`:''});
